{
  "terms": [
    {
      "term": "Statutory Implications",
      "simpleDefinition": "The legal consequences, such as criminal prosecution or fines, that result from breaking a law or regulation.",
      "anchor": "Criminal penalties enforced by the government.",
      "misconception": "Believing that statutory breaches only result in small fines rather than potential imprisonment."
    },
    {
      "term": "Non-statutory Implications",
      "simpleDefinition": "The professional and commercial consequences, such as losing a job or reputation, for failing to follow industry standards.",
      "anchor": "Career-ending fallout and loss of business.",
      "misconception": "Thinking that non-statutory means 'optional' with no real-world consequences."
    },
    {
      "term": "Improvement Notice",
      "simpleDefinition": "A legal document issued by an inspector requiring a safety breach to be fixed within a specific time limit.",
      "anchor": "A 'fix it by this date' legal order.",
      "misconception": "Confusing an improvement notice with a simple verbal warning."
    },
    {
      "term": "Prohibition Notice",
      "simpleDefinition": "A legal document that stops all work activity immediately because of a serious risk of personal injury.",
      "anchor": "An 'immediate stop work' legal order.",
      "misconception": "Thinking work can continue while you try to fix the problem mentioned in the notice."
    },
    {
      "term": "Prosecution",
      "simpleDefinition": "The process of taking legal action against an individual or company in a criminal court.",
      "anchor": "Facing a judge for a criminal offense.",
      "misconception": "Thinking prosecution only happens if someone is killed; it can happen for any serious safety breach."
    },
    {
      "term": "Reputational Damage",
      "simpleDefinition": "The loss of trust and professional standing that makes it difficult to find future work or clients.",
      "anchor": "Nobody wanting to hire you because of your track record.",
      "misconception": "Assuming that reputational damage is less severe than a legal fine."
    }
  ],
  "anchorPhrases": [
    "Statutory breaches lead to criminal prosecution.",
    "Non-statutory failures can end your career.",
    "A prohibition notice stops work instantly.",
    "An improvement notice gives you a deadline to fix a fault.",
    "Breaching the EAWR is a criminal offense."
  ],
  "misconceptionTargets": [
    "Non-statutory means optional.",
    "Statutory breaches only result in small fines.",
    "Prohibition and improvement notices are the same thing.",
    "Professional dismissal is not as serious as a legal notice."
  ]
}

{
  "teachChecks": [
    {
      "key": "203-1b-teach-check-1",
      "title": "Statutory Implications",
      "objective": "Identify the legal consequences of breaching statutory regulations like EAWR or HASAWA.",
      "retrievalTextLines": [
        "Statutory regulations, such as the Electricity at Work Regulations (EAWR) and the Health and Safety at Work Act (HASAWA), are the law of the land. If you breach these, you are committing a criminal offense, not just a professional mistake.",
        "The Health and Safety Executive (HSE) has the power to issue enforcement notices to ensure safety. An improvement notice is a legal order requiring you to fix a safety breach within a specific timeframe. If the risk is more severe and immediate, a prohibition notice will be issued, which stops all work activity instantly until the danger is removed.",
        "Beyond these notices, the most serious consequences include prosecution in a criminal court. This process can lead to heavy fines for a company or even imprisonment for an individual electrician. These are criminal penalties designed to punish negligence and prevent injury or death on site. You must understand that a statutory breach is a matter for the police and the courts, potentially leading to a permanent criminal record."
      ],
      "hint": "Focus on the legal enforcement actions like notices, fines, and the threat of jail time."
    },
    {
      "key": "203-1b-teach-check-2",
      "title": "Non-statutory Implications",
      "objective": "Identify the professional and commercial consequences of failing to follow non-statutory guidance like BS 7671.",
      "retrievalTextLines": [
        "Non-statutory regulations, like BS 7671 (The IET Wiring Regulations) or the On-Site Guide, are industry standards rather than direct laws. However, do not mistake 'non-statutory' for 'optional.' Ignoring these standards carries heavy professional and commercial weight.",
        "If you fail to follow these standards, you risk immediate dismissal from your job or losing your registration with professional bodies like the NICEIC or NAPIT. This leads to a significant loss of earnings and the loss of future clients who require certified proof of competence. Reputational damage is often permanent; in the electrical trade, once you are known for unsafe or substandard work, it becomes incredibly difficult to find employment.",
        "Most importantly, non-compliance with these standards is the leading cause of injury or death in the electrical industry. While you might not go to jail directly for a BS 7671 breach, if that breach leads to an accident, it will be used as evidence in court to prove you failed your statutory duties. Professional fallout can be just as career-ending as a legal fine."
      ],
      "hint": "Think about how your career, your wallet, and your reputation suffer when you ignore industry standards."
    }
  ]
}

