{
  "integrative": {
    "title": "Integrative Close: The Cost of Non-compliance",
    "objective": "Evaluate a site failure to identify both the immediate legal penalties and the long-term commercial impacts on an electrical contractor.",
    "retrievalTextLines": [
      "Statutory implications are legal penalties enforced by the state, such as prosecution, fines, and HSE notices.",
      "Non-statutory implications involve professional fallout, such as dismissal, loss of clients, and reputational damage.",
      "A Prohibition Notice is a statutory tool used to stop dangerous work immediately.",
      "While BS 7671 is non-statutory, failing to follow it is often used as evidence of a statutory breach of the Electricity at Work Regulations."
    ],
    "questionText": "An electrical contractor is found to have left live, uninsulated busbars exposed in a public area while on a break, creating an immediate danger of death. The HSE inspector intervenes. Name the specific statutory notice that will be issued to stop the work instantly, and explain how this legal intervention leads to a specific non-statutory consequence regarding the contractor's future business.",
    "answerGuidance": [
      "Prohibition Notice (Statutory)",
      "Reputational damage (Non-statutory)",
      "Loss of clients or loss of earnings (Non-statutory)",
      "The statutory notice stops the job, which then leads to a loss of professional reputation or the loss of future clients."
    ],
    "hint": "Focus on the specific legal order used for 'immediate' danger, and then consider how that public enforcement action affects the contractor's ability to win more work."
  }
}

